<template>
    <div class="mail-wrapper">
        <div class="mail-content">
            <div class="mail-field">
                <div class="title">收件人</div>
                <a-input class="text" type="email" v-model:value="mailParams.receiver" placeholder="请输入收件人邮箱" />
            </div>
            <div class="mail-field">
                <div class="title">标题</div>
                <a-input class="text" v-model:value="mailParams.title" placeholder="请输入标题" />
            </div>
            <div class="mail-field mail-md-field">
                <div class="title">正文</div>
                <div class="content">
                    <v-md-editor v-model="mailParams.content" class="md-editor" @change="mdChange" :disabled-menus="[]" @copy-code-success="handleCopyCodeSuccess" @upload-image="handleUploadImage"></v-md-editor>
                </div>
            </div>
            <div class="btns">
                <a-button style="margin-right:16px" @click="cancelMail()">取消</a-button>
                <a-button type="primary" @click="sendMail()">确认</a-button>
            </div>
        </div>
    </div>
</template>
<script>
import { inject, reactive } from "vue";
import { useStore } from "vuex";
import { useRouter } from "vue-router";
import { message } from "ant-design-vue";

export default {
    setup() {
        const router = useRouter();
        const store = useStore();
        const $api = inject("$api");

        let mailParams = reactive({
            title: null,
            receiver: null,
            content: "",
            html: null,
            sender: store.state.userInfo.email,
            imageFileIds: []
        });

        const mdChange = (text, htmlValue) => {
            mailParams.html = htmlValue;
        };

        // 代码复制
        const handleCopyCodeSuccess = () => {
            message.success("代码已复制");
        };

        // 上传图片
        const handleUploadImage = (event, insertImage, files) => {
            // 拿到 files 之后上传到文件服务器，然后向编辑框中插入对应的内容
            const formData = new FormData();
            formData.append("file", files[0]);
            formData.append("cloudPath", "mail/");
            $api.common.uploadImage(formData).then((res) => {
                insertImage({
                    url: res.data.tempFileURL,
                    desc: files[0].name,
                    width: "auto",
                    height: "auto"
                });
                mailParams.imageFileIds.push(res.data.fileID);
            });
        };

        // 取消发送邮件
        const cancelMail = () => {
            router.push({ path: "/home" });
        };
        // 发送邮件
        const sendMail = () => {
            if (!mailParams.receiver) {
                message.error("收件人不能为空");
                return;
            }
            if (!mailParams.title) {
                message.error("标题不能为空");
                return;
            }
            let pattern = /^[A-Za-z0-9\u4e00-\u9fa5]+@[a-zA-Z0-9_-]+(\.[a-zA-Z0-9_-]+)+$/;
            if (!pattern.test(mailParams.receiver)) {
                message.error("邮箱格式不正确");
                return;
            }
            $api.common.sendMail(mailParams).then(() => {
                message.success("发送成功");
                cancelMail();
            });
        };

        return {
            sendMail,
            cancelMail,
            mailParams,
            mdChange,
            handleUploadImage,
            handleCopyCodeSuccess
        };
    }
};
</script>

<style lang="scss">
.mail-wrapper {
    width: 100%;
    height: 100%;
    overflow: auto;

    .mail-content {
        display: flex;
        width: 1136px;
        margin: 16px auto;
        flex-direction: column;
        box-shadow: 0 1px 8px 0 rgba(0, 0, 0, 0.1);
        padding: 16px;
        min-height: calc(100% - 32px);

        .mail-field {
            margin-top: 16px;
            display: flex;
            align-items: center;

            &:first-of-type {
                margin-top: 0;
            }

            .title {
                margin-right: 16px;
                width: 60px;
            }

            .text {
                flex: 1;
            }

            &.mail-md-field {
                flex: 1;
                max-height: 700px;
                align-items: flex-start;

                .content {
                    border: 1px solid #ececec;
                    align-self: stretch;
                    flex: 1;

                    .md-editor {
                        width: 100%;
                        height: 100%;
                    }
                }
            }
        }

        .btns {
            margin-top: 16px;
            display: flex;
            justify-content: flex-end;
        }
    }
}
</style>
